function useGoogleFonts() {
  useEffect(() => {
    const id = "fg-fonts";
    if (document.getElementById(id)) return;
    const link = document.createElement("link");
    link.id = id;
    link.rel = "stylesheet";
    link.href =
      "https://fonts.googleapis.com/css2?family=Playfair+Display:wght@600;700;800&family=Inter:wght@400;500;600;700&display=swap";
    document.head.appendChild(link);
  }, []);
}

function Mark({ size = 40 }) {
  // Stylized "G" mark echoing the real Genebra EAD logo: maroon outer arc + charcoal inner G
  return (
    <svg width={size} height={size} viewBox="0 0 64 64" fill="none">
      <path
        d="M48 14 A22 22 0 1 0 48 50"
        stroke={theme.maroon}
        strokeWidth="9"
        strokeLinecap="round"
        fill="none"
      />
      <path
        d="M44 32 H30 M44 32 V44"
        stroke={theme.charcoal}
        strokeWidth="9"
        strokeLinecap="round"
        fill="none"
      />
    </svg>
  );
}

function Initials({ name, size = 36, bg = theme.charcoal, color = "#F0E6D8" }) {
  const initials = (name || "?")
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((w) => w[0].toUpperCase())
    .join("");
  return (
    <div
      style={{
        width: size,
        height: size,
        borderRadius: "50%",
        background: bg,
        color: color,
        fontFamily: displayFont,
        fontWeight: 700,
        fontSize: size * 0.4,
      }}
      className="flex items-center justify-center flex-shrink-0"
    >
      {initials}
    </div>
  );
}

